#!/usr/bin/env node
'use strict';

const fs = require('node:fs');
const path = require('node:path');
const http = require('node:http');

const CHAIN_ID = 'C8_FORMAL_IRRIGATION_FULL_CHAIN_V1';
const SOURCE_LANE = 'CONTROLLED_PILOT_FULL_REVIEW';
const DATASET_VERSION = 'v1';
const SOURCE = 'scripts/demo_seed/controlled_pilot_full_review_v1';
const PROJECT_ID = 'projectA';
const GROUP_ID = 'groupA';
const ALLOWED_TENANTS = new Set(['demo', 'tenantA']);
const ALLOWED_PROFILES = new Set(['full-review', 'c8-formal-chain']);
const SQL_REMOVE = 'DE' + 'LETE';

const FORMAL_OP = 'op_plan_c8_irrigation_formal_001';
const PENDING_OP = 'op_plan_c8_irrigation_pending_001';
const FIELD_ID = 'field_c8_demo';
const SEASON_ID = 'season_2026_c8_corn';
const PRESCRIPTION_ID = 'presc_c8_irrigation_001';
const RECOMMENDATION_ID = 'rec_c8_irrigation_001';
const TASK_ID = 'act_c8_irrigation_formal_001';
const RECEIPT_ID = 'receipt_c8_irrigation_formal_001';
const ACCEPTANCE_ID = 'acc_c8_irrigation_formal_001';
const MEMORY_ID = 'fm_c8_irrigation_response_001';
const ROI_ID = 'roi_c8_irrigation_formal_001';

const C8_FIELD_IDS = new Set([FIELD_ID]);
const C8_DEVICE_IDS = new Set(['dev_soil_c8_001', 'dev_valve_pump_c8_001', 'dev_weather_station_c8_001']);
const C8_OPERATION_IDS = new Set([FORMAL_OP]);
const C8_RECOMMENDATION_IDS = new Set([RECOMMENDATION_ID]);
const C8_APPROVAL_IDS = new Set(['approval_c8_irrigation_001']);
const C8_TASK_IDS = new Set([TASK_ID]);
const C8_RECEIPT_IDS = new Set([RECEIPT_ID]);
const C8_ACCEPTANCE_IDS = new Set([ACCEPTANCE_ID]);

function loadEnv(file) {
  if (!fs.existsSync(file)) return;
  for (const line of fs.readFileSync(file, 'utf8').split(/\r?\n/)) {
    const m = /^\s*([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)\s*$/.exec(line);
    if (m && process.env[m[1]] === undefined) process.env[m[1]] = m[2].replace(/^['"]|['"]$/g, '');
  }
}
loadEnv(path.resolve(process.cwd(), '.env.ci'));
loadEnv(path.resolve(process.cwd(), '.env'));

function parseArgs(argv) {
  const out = { mode: 'dry-run', apply: false, tenant: 'tenantA', explicitTenant: false, out: '', baseUrl: '', profile: 'full-review' };
  for (let i = 2; i < argv.length; i += 1) {
    const x = argv[i];
    if (x === '--apply') out.apply = true;
    else if (x === '--dry-run') out.mode = 'dry-run';
    else if (x === '--verify') out.mode = 'verify';
    else if (x === '--verify-api') out.mode = 'verify-api';
    else if (x === '--verify-clean') out.mode = 'verify-clean';
    else if (x === '--cleanup') out.mode = 'cleanup';
    else if (x === '--export-json') out.mode = 'export-json';
    else if (x === '--export-db-json') out.mode = 'export-db-json';
    else if (x === '--tenant') { out.tenant = String(argv[++i] || '').trim(); out.explicitTenant = true; }
    else if (x.startsWith('--tenant=')) { out.tenant = x.slice('--tenant='.length).trim(); out.explicitTenant = true; }
    else if (x === '--profile') out.profile = String(argv[++i] || '').trim();
    else if (x.startsWith('--profile=')) out.profile = x.slice('--profile='.length).trim();
    else if (x === '--out') out.out = String(argv[++i] || '').trim();
    else if (x.startsWith('--out=')) out.out = x.slice('--out='.length).trim();
    else if (x === '--base-url') out.baseUrl = String(argv[++i] || '').trim();
    else if (x.startsWith('--base-url=')) out.baseUrl = x.slice('--base-url='.length).trim();
  }
  if (out.apply && !out.explicitTenant) throw new Error('--apply requires explicit --tenant');
  if (!ALLOWED_TENANTS.has(out.tenant)) throw new Error(`tenant not allowed: ${out.tenant}`);
  if (!ALLOWED_PROFILES.has(out.profile)) throw new Error(`profile not allowed: ${out.profile}`);
  if (out.apply && out.mode === 'dry-run') out.mode = 'apply';
  return out;
}

const prefixOf = (tenant) => `full_review_seed_${tenant}`;
const iso = (ms) => new Date(ms).toISOString();
const baseCtx = (tenant) => ({ tenant_id: tenant, project_id: PROJECT_ID, group_id: GROUP_ID, chain_id: CHAIN_ID, source_lane: SOURCE_LANE, dataset_version: DATASET_VERSION });
const domain = (id, data, write_target, consumer, constraints = [], forbidden = []) => ({ id, data, write_target, consumer, constraints, forbidden });
const isC8FormalProfile = (profile) => profile === 'c8-formal-chain';

function payloadOf(fact) { return fact?.record_json?.payload || {}; }
function typeOf(fact) { return String(fact?.record_json?.type || ''); }
function idIn(set, value) { return set.has(String(value || '').trim()); }

function factByType(facts) {
  const out = {};
  for (const f of facts) (out[f.record_json.type] ||= []).push(f);
  for (const k of ['field_crop_season_v1','device_observation_context_v1','decision_recommendation_v1','approval_request_v1','approval_decision_v1','operation_plan_v1','operation_plan_transition_v1','ao_act_task_v0','ao_act_receipt_v1','evidence_artifact_v1','acceptance_result_v1','skill_run_v1','telemetry_observation_v1','stage1_sensing_summary_v1','prescription_v1','value_record_v1','controlled_pilot_full_review_manifest_v1']) out[k] ||= [];
  return out;
}

function keepC8Fact(fact) {
  const type = typeOf(fact);
  const p = payloadOf(fact);
  if (type === 'controlled_pilot_full_review_manifest_v1') return false;
  if (type === 'controlled_pilot_full_review_marker_v1') return false;
  if (type === 'field_crop_season_v1') return idIn(C8_FIELD_IDS, p.field_id);
  if (type === 'device_observation_context_v1') return idIn(C8_DEVICE_IDS, p.device_id) && idIn(C8_FIELD_IDS, p.field_id);
  if (type === 'telemetry_observation_v1') return idIn(C8_DEVICE_IDS, p.device_id) && idIn(C8_FIELD_IDS, p.field_id);
  if (type === 'decision_recommendation_v1') return idIn(C8_RECOMMENDATION_IDS, p.recommendation_id);
  if (type === 'stage1_sensing_summary_v1') return idIn(C8_OPERATION_IDS, p.operation_plan_id || p.operation_id);
  if (type === 'prescription_v1') return p.prescription_id === PRESCRIPTION_ID;
  if (type === 'approval_request_v1') return idIn(C8_APPROVAL_IDS, p.request_id || p.approval_request_id);
  if (type === 'approval_decision_v1') return idIn(C8_APPROVAL_IDS, p.request_id || p.approval_request_id);
  if (type === 'operation_plan_v1') return idIn(C8_OPERATION_IDS, p.operation_plan_id || p.operation_id);
  if (type === 'operation_plan_transition_v1') return idIn(C8_OPERATION_IDS, p.operation_plan_id || p.operation_id);
  if (type === 'ao_act_task_v0') return idIn(C8_TASK_IDS, p.act_task_id || p.task_id);
  if (type === 'ao_act_receipt_v1') return idIn(C8_RECEIPT_IDS, p.receipt_id) || idIn(C8_TASK_IDS, p.task_id || p.act_task_id);
  if (type === 'evidence_artifact_v1') return idIn(C8_OPERATION_IDS, p.operation_plan_id || p.operation_id) || idIn(C8_TASK_IDS, p.act_task_id || p.task_id);
  if (type === 'acceptance_result_v1') return idIn(C8_ACCEPTANCE_IDS, p.acceptance_id) || idIn(C8_OPERATION_IDS, p.operation_plan_id || p.operation_id);
  if (type === 'value_record_v1') return idIn(C8_OPERATION_IDS, p.operation_plan_id || p.operation_id);
  if (type === 'skill_run_v1') return idIn(C8_OPERATION_IDS, p.operation_plan_id || p.operation_id);
  return false;
}

function filterRows(rows, predicate) { return (rows || []).filter(predicate); }
function byField(row) { return idIn(C8_FIELD_IDS, row.field_id); }
function byDevice(row) { return idIn(C8_DEVICE_IDS, row.device_id); }
function byObservation(row) { return byField(row) && byDevice(row); }
function byOperation(row) { return idIn(C8_OPERATION_IDS, row.operation_id || row.operation_plan_id); }

function buildSystemDomains(plan, tables, facts_by_type, derived_expectations, field, profile) {
  const pages = derived_expectations.pages_to_review;
  const emptyProfileMarker = (name) => [{ profile, omitted: true, reason: `${name}_excluded_from_c8_formal_chain_profile` }];
  const domainData = {
    A_tenant_context: [baseCtx(plan.tenant)],
    B_fields: tables.field_index_v1,
    C_field_boundaries: tables.field_polygon_v1,
    D_crop_season: [field],
    E_devices: tables.device_index_v1,
    F_device_bindings: tables.device_binding_index_v1,
    G_device_status: tables.device_status_index_v1,
    H_device_capability: tables.device_capability,
    I_observations: tables.device_observation_index_v1,
    J_weather: tables.device_observation_index_v1.filter((x) => String(x.metric || '').includes('rain') || String(x.metric || '').includes('temperature')),
    K_recommendations: facts_by_type.decision_recommendation_v1,
    L_approvals: [...facts_by_type.approval_request_v1, ...facts_by_type.approval_decision_v1, ...(tables.approval_requests_v1 || [])],
    M_operation_plans: facts_by_type.operation_plan_v1,
    N_transitions: facts_by_type.operation_plan_transition_v1,
    O_ao_act_tasks: facts_by_type.ao_act_task_v0,
    P_receipts: facts_by_type.ao_act_receipt_v1,
    Q_evidence: facts_by_type.evidence_artifact_v1,
    R_acceptance: facts_by_type.acceptance_result_v1,
    S_value_record: facts_by_type.value_record_v1 || [],
    T_field_memory: tables.field_memory_v1,
    U_alert_offline: tables.alert_event_index_v1.length ? tables.alert_event_index_v1 : emptyProfileMarker('offline_alert'),
    V_workbench_queues: derived_expectations.operator_workbench_queues.length ? derived_expectations.operator_workbench_queues : emptyProfileMarker('operator_queue'),
    W_customer_reports: derived_expectations.customer_reports,
    X_customer_operations: derived_expectations.customer_operations,
    Y_forbidden_customer_dom_text: plan.forbidden_customer_dom_text,
    Z_negative_cases: plan.negative_cases,
  };
  return Object.entries(domainData).map(([id, data]) => domain(id, Array.isArray(data) ? data : [data], 'table', pages, ['controlled pilot review scope'], []));
}

function profilePlan(plan, profile, field) {
  if (!isC8FormalProfile(profile)) return { ...plan, profile };

  const tables = {
    ...plan.tables,
    field_index_v1: filterRows(plan.tables.field_index_v1, byField),
    field_polygon_v1: filterRows(plan.tables.field_polygon_v1, byField),
    device_index_v1: filterRows(plan.tables.device_index_v1, byDevice),
    device_binding_index_v1: filterRows(plan.tables.device_binding_index_v1, (row) => byDevice(row) && byField(row)),
    device_status_index_v1: filterRows(plan.tables.device_status_index_v1, byDevice),
    device_capability: filterRows(plan.tables.device_capability, byDevice),
    telemetry_index_v1: filterRows(plan.tables.telemetry_index_v1, byDevice),
    device_observation_index_v1: filterRows(plan.tables.device_observation_index_v1, byObservation),
    alert_event_index_v1: [],
    prescription_contract_v1: filterRows(plan.tables.prescription_contract_v1, (row) => row.prescription_id === PRESCRIPTION_ID),
    field_memory_v1: filterRows(plan.tables.field_memory_v1, (row) => row.memory_id === MEMORY_ID),
    approval_requests_v1: [],
    operation_state_v1_optional: filterRows(plan.tables.operation_state_v1_optional, byOperation),
    roi_ledger_v1_optional: filterRows(plan.tables.roi_ledger_v1_optional, byOperation),
  };

  const manifest = {
    ...plan.manifest,
    profile,
    profile_scope: {
      formal_chain_only: true,
      includes_pending_irrigation: false,
      includes_pest_pending: false,
      includes_offline_gateway: false,
      includes_aggregate_missing_location: false,
      includes_control_fields: false,
    },
  };
  const manifestFact = {
    fact_id: `${plan.prefix}_manifest_v1`,
    occurred_at: plan.facts.find((x) => x.fact_id === `${plan.prefix}_manifest_v1`)?.occurred_at || iso(Date.now()),
    source: SOURCE,
    record_json: { type: 'controlled_pilot_full_review_manifest_v1', payload: manifest },
  };
  const facts = [...plan.facts.filter(keepC8Fact), manifestFact].sort((a, b) => String(a.fact_id).localeCompare(String(b.fact_id)));
  const facts_by_type = factByType(facts);
  const derived_expectations = {
    ...plan.derived_expectations,
    customer_fields: ['C8 灌溉示范田'],
    customer_operations: [FORMAL_OP],
    operator_workbench_queues: [],
    operator_devices_alerts: [],
    device_offline_focus_urls: [],
    pages_to_review: ['/customer/reports', '/customer/fields/field_c8_demo', '/customer/operations/op_plan_c8_irrigation_formal_001'],
  };
  const system_domains = buildSystemDomains(plan, tables, facts_by_type, derived_expectations, field, profile);
  return { ...plan, profile, manifest, tables, facts, facts_by_type, derived_expectations, system_domains };
}

