function dbConfig() { if (process.env.DATABASE_URL || process.env.POSTGRES_URL) return { connectionString: process.env.DATABASE_URL || process.env.POSTGRES_URL }; return { host: process.env.PGHOST || '127.0.0.1', port: Number(process.env.PGPORT || 5433), user: process.env.PGUSER || 'landos', password: process.env.PGPASSWORD || 'landos_pwd', database: process.env.PGDATABASE || 'landos' }; }
