async function withClient(fn) { const p = pool(); const c = await p.connect(); try { return await fn(c); } finally { c.release(); await p.end(); } }
async function tableExists(c, t) { const r = await c.query('SELECT to_regclass($1)::text AS name', [`public.${t}`]); return Boolean(r.rows[0]?.name); }
async function cols(c, t) { if (!(await tableExists(c, t))) return new Set(); const r = await c.query("SELECT column_name FROM information_schema.columns WHERE table_schema='public' AND table_name=$1", [t]); return new Set(r.rows.map((x) => String(x.column_name))); }
async function insertRows(c, table, rows, conflictCols = []) { const cs = await cols(c, table); if (!cs.size) return false; for (const row of rows) { const keys = Object.keys(row).filter((k) => cs.has(k)); if (!keys.length) continue; const vals = keys.map((k) => (Array.isArray(row[k]) || (row[k] && typeof row[k] === 'object')) ? JSON.stringify(row[k]) : row[k]); const conflict = conflictCols.length && conflictCols.every((k) => keys.includes(k)) ? ` ON CONFLICT (${conflictCols.join(',')}) DO UPDATE SET ${keys.filter((k) => !conflictCols.includes(k)).map((k) => `${k}=EXCLUDED.${k}`).join(',') || `${conflictCols[0]}=EXCLUDED.${conflictCols[0]}`}` : ''; await c.query(`INSERT INTO ${table} (${keys.join(',')}) VALUES (${keys.map((_, i) => `$${i + 1}`).join(',')})${conflict}`, vals); } return true; }
async function removeOwned(c, table, tenant, idCol, ids) { const cs = await cols(c, table); if (!cs.has(idCol)) return; await c.query(`${SQL_REMOVE} FROM ${table} WHERE ${cs.has('tenant_id') ? 'tenant_id=$1 AND ' : ''}${idCol}=ANY($${cs.has('tenant_id') ? 2 : 1}::text[])`, cs.has('tenant_id') ? [tenant, ids] : [ids]); }
async function readOwned(c, table, tenant, idCol, ids) { const cs = await cols(c, table); if (!cs.has(idCol)) return []; const r = await c.query(`SELECT * FROM ${table} WHERE ${cs.has('tenant_id') ? 'tenant_id=$1 AND ' : ''}${idCol}=ANY($${cs.has('tenant_id') ? 2 : 1}::text[])`, cs.has('tenant_id') ? [tenant, ids] : [ids]); return r.rows ?? []; }
async function requiredTables(c) { const miss = []; for (const t of ['facts','field_index_v1','field_polygon_v1','device_index_v1','device_binding_index_v1','device_status_index_v1','device_capability','telemetry_index_v1','device_observation_index_v1','alert_event_index_v1','prescription_contract_v1','field_memory_v1']) if (!(await tableExists(c, t))) miss.push(t); return miss; }
async function clearOwnedBeforeApply(c, p) { const m = p.manifest.seed_owned_ids; await removeOwned(c, 'operation_state_v1', p.tenant, 'operation_id', m.operations); await removeOwned(c, 'approval_requests_v1', p.tenant, 'approval_request_id', m.approval_requests); await removeOwned(c, 'roi_ledger_v1', p.tenant, 'roi_ledger_id', [ROI_ID]); await removeOwned(c, 'field_memory_v1', p.tenant, 'memory_id', m.field_memory); await removeOwned(c, 'prescription_contract_v1', p.tenant, 'prescription_id', m.prescriptions); await removeOwned(c, 'alert_event_index_v1', p.tenant, 'event_id', m.alerts); await c.query(`${SQL_REMOVE} FROM device_observation_index_v1 WHERE tenant_id=$1 AND fact_id LIKE $2`, [p.tenant, `${p.prefix}_%`]).catch(() => {}); await c.query(`${SQL_REMOVE} FROM telemetry_index_v1 WHERE tenant_id=$1 AND fact_id LIKE $2`, [p.tenant, `${p.prefix}_%`]).catch(() => {}); for (const table of ['device_capability','device_status_index_v1','device_binding_index_v1','device_index_v1']) await removeOwned(c, table, p.tenant, 'device_id', m.devices); await removeOwned(c, 'field_polygon_v1', p.tenant, 'field_id', m.fields); await removeOwned(c, 'field_index_v1', p.tenant, 'field_id', m.fields); await c.query(`${SQL_REMOVE} FROM facts WHERE fact_id LIKE $1`, [`${p.prefix}_%`]); }
function apiHeaders(tenant = 'tenantA') { const token = process.env.GEOX_AO_ACT_TOKEN || process.env.GEOX_ACCEPTANCE_TOKEN || process.env.GEOX_EXECUTOR_TOKEN || process.env.ADMIN_TOKEN || 'tenant_a_admin_token'; return { accept: 'application/json', 'content-type': 'application/json', authorization: `Bearer ${token}`, 'x-geox-token': token, 'x-geox-ao-act-token': token, 'x-ao-act-token': token, 'x-tenant-id': tenant, 'x-project-id': PROJECT_ID, 'x-group-id': GROUP_ID }; }
function tryJson(raw) { try { return JSON.parse(raw); } catch { return null; } }
function httpRequest(method, url, body, tenant) { return new Promise((resolve) => { const parsed = new URL(url); const data = body == null ? '' : JSON.stringify(body); const req = http.request({ method, hostname: parsed.hostname, port: parsed.port, path: `${parsed.pathname}${parsed.search}`, headers: { ...apiHeaders(tenant), ...(data ? { 'content-length': Buffer.byteLength(data) } : {}) } }, (res) => { let raw = ''; res.on('data', (d) => { raw += d; }); res.on('end', () => resolve({ status: res.statusCode || 0, raw, json: tryJson(raw) })); }); req.on('error', (e) => resolve({ status: 0, raw: String(e.message || e), json: null })); req.setTimeout(3000, () => { req.destroy(); resolve({ status: 0, raw: 'timeout', json: null }); }); if (data) req.write(data); req.end(); }); }
function scoped(tenant, extra = {}) { return { tenant_id: tenant, project_id: PROJECT_ID, group_id: GROUP_ID, ...extra }; }
async function deriveAsExecutedIfRequested(p, baseUrl) { if (!baseUrl) return { skipped: true, reason: 'as-executed derivation skipped: --base-url not provided' }; const base = baseUrl.replace(/\/+$/, ''); const r = await httpRequest('POST', `${base}/api/v1/as-executed/from-receipt`, scoped(p.tenant, { task_id: TASK_ID, receipt_id: RECEIPT_ID }), p.tenant); if (r.status >= 200 && r.status < 300 && r.json?.as_executed) return { skipped: false, as_executed_id: r.json.as_executed.as_executed_id, status: r.json.as_executed.executed?.status }; return { skipped: true, reason: `as-executed derivation skipped: ${r.status || 0} ${r.raw || ''}`.slice(0, 240) }; }
async function apply(p, baseUrl = '') { return withClient(async (c) => { const missing = await requiredTables(c); if (missing.length) throw new Error(`missing tables: ${missing.join(',')}`); let locked = false; await c.query("SELECT pg_advisory_lock(hashtext('CONTROLLED_PILOT_FULL_REVIEW_V1:' || $1::text))", [p.tenant]); locked = true; try { await c.query('BEGIN'); await clearOwnedBeforeApply(c, p); const keyMap = { field_index_v1:['tenant_id','field_id'], field_polygon_v1:['tenant_id','field_id'], device_index_v1:['tenant_id','device_id'], device_binding_index_v1:['tenant_id','device_id','field_id'], device_status_index_v1:['tenant_id','device_id'], device_capability:['tenant_id','device_id'], telemetry_index_v1:['tenant_id','device_id','metric','ts'], device_observation_index_v1:['tenant_id','device_id','metric','observed_at_ts_ms'], alert_event_index_v1:['tenant_id','event_id'], field_memory_v1:['memory_id'], prescription_contract_v1:['tenant_id','project_id','group_id','recommendation_id'] }; for (const [table, rows] of Object.entries(p.tables)) { if (table.endsWith('_optional') || table === 'approval_requests_v1' || table === 'prescription_contract_v1') continue; await insertRows(c, table, rows, keyMap[table] || []); } await insertRows(c, 'prescription_contract_v1', p.tables.prescription_contract_v1, ['tenant_id','project_id','group_id','recommendation_id']); await insertRows(c, 'operation_state_v1', p.tables.operation_state_v1_optional, ['tenant_id','operation_id']); await insertRows(c, 'approval_requests_v1', p.tables.approval_requests_v1, ['tenant_id','approval_request_id']); await insertRows(c, 'roi_ledger_v1', p.tables.roi_ledger_v1_optional, []); await insertRows(c, 'facts', p.facts, ['fact_id']); await c.query('COMMIT'); const derivation = await deriveAsExecutedIfRequested(p, baseUrl); return { ok: true, apply: true, tenant: p.tenant, profile: p.profile, chain_id: p.chain_id, written: { facts: p.facts.length, fields: p.tables.field_index_v1.length, devices: p.tables.device_index_v1.length, alerts: p.tables.alert_event_index_v1.length, field_memory: p.tables.field_memory_v1.length, prescriptions: p.tables.prescription_contract_v1.length }, as_executed_derivation: derivation, warnings: derivation.skipped ? [derivation.reason] : [] }; } catch (e) { await c.query('ROLLBACK').catch(() => {}); throw e; } finally { if (locked) await c.query("SELECT pg_advisory_unlock(hashtext('CONTROLLED_PILOT_FULL_REVIEW_V1:' || $1::text))", [p.tenant]).catch(() => {}); } }); }
async function verify(p) { return withClient(async (c) => { const missing = await requiredTables(c); if (missing.length) throw new Error(`missing tables: ${missing.join(',')}`); const checks = {}; async function one(name, sql, params) { const r = await c.query(sql, params); checks[name] = Number(r.rows[0].count); if (checks[name] < 1) throw new Error(`verify failed: ${name}`); } async function zero(name, sql, params) { const r = await c.query(sql, params); checks[name] = Number(r.rows[0].count); if (checks[name] !== 0) throw new Error(`verify failed: ${name}`); } await one('chain_manifest', "SELECT count(*) FROM facts WHERE fact_id LIKE $1 AND record_json->>'type'='controlled_pilot_full_review_manifest_v1' AND record_json->'payload'->>'chain_id'=$2 AND record_json->'payload'->>'profile'=$3", [`${p.prefix}_%`, CHAIN_ID, p.profile]); await one('field_crop_season', "SELECT count(*) FROM facts WHERE fact_id LIKE $1 AND record_json->>'type'='field_crop_season_v1' AND record_json->'payload'->>'season_id'=$2", [`${p.prefix}_%`, SEASON_ID]); await one(isC8FormalProfile(p.profile) ? 'devices_3' : 'devices_4', isC8FormalProfile(p.profile) ? "SELECT count(*) FROM device_index_v1 WHERE tenant_id=$1 AND device_id IN ('dev_soil_c8_001','dev_valve_pump_c8_001','dev_weather_station_c8_001')" : "SELECT count(*) FROM device_index_v1 WHERE tenant_id=$1 AND device_id IN ('dev_soil_c8_001','dev_valve_pump_c8_001','dev_gateway_offline_001','dev_weather_station_c8_001')", [p.tenant]); await one('observation_context', "SELECT count(*) FROM facts WHERE fact_id LIKE $1 AND record_json->>'type'='telemetry_observation_v1' AND record_json->'payload'->>'metric_label' IS NOT NULL AND record_json->'payload'->>'diagnostic_use' IS NOT NULL", [`${p.prefix}_%`]); await one('prescription', "SELECT count(*) FROM prescription_contract_v1 WHERE tenant_id=$1 AND prescription_id=$2 AND operation_amount::jsonb#>>'{metadata,trace_id}'='skill_trace_c8_irrigation_001'", [p.tenant, PRESCRIPTION_ID]); await one('formal_receipt', "SELECT count(*) FROM facts WHERE fact_id LIKE $1 AND record_json->>'type'='ao_act_receipt_v1' AND record_json->'payload'->>'receipt_id'=$2 AND record_json->'payload'->>'status'='executed'", [`${p.prefix}_%`, RECEIPT_ID]); await one('formal_acceptance_gate', "SELECT count(*) FROM facts WHERE fact_id LIKE $1 AND record_json->>'type'='acceptance_result_v1' AND record_json->'payload'->>'acceptance_id'=$2 AND record_json->'payload'->>'formal_acceptance'='true' AND record_json->'payload'->>'chain_validation_passed'='true'", [`${p.prefix}_%`, ACCEPTANCE_ID]); await one('field_memory_formal', "SELECT count(*) FROM field_memory_v1 WHERE tenant_id=$1 AND memory_id=$2 AND memory_lane='FORMAL_FIELD_MEMORY' AND trust_level='FORMAL_ACCEPTED' AND customer_visible_memory=true AND learning_eligible=true", [p.tenant, MEMORY_ID]); if (isC8FormalProfile(p.profile)) { await zero('no_pending_operation', "SELECT count(*) FROM facts WHERE fact_id LIKE $1 AND record_json->>'type'='operation_plan_v1' AND record_json->'payload'->>'operation_plan_id'=$2", [`${p.prefix}_%`, PENDING_OP]); await zero('no_pest_pending', "SELECT count(*) FROM facts WHERE fact_id LIKE $1 AND record_json::jsonb#>>'{payload,recommendation_id}'='rec_c8_pest_inspection_pending_001'", [`${p.prefix}_%`]); await zero('no_offline_gateway', "SELECT count(*) FROM device_index_v1 WHERE tenant_id=$1 AND device_id='dev_gateway_offline_001'", [p.tenant]); await zero('no_aggregate_alert', "SELECT count(*) FROM alert_event_index_v1 WHERE tenant_id=$1 AND event_id='alert_aggregate_missing_location_001'", [p.tenant]); } return { ok: true, verify: true, tenant: p.tenant, profile: p.profile, chain_id: p.chain_id, checks, warnings: [] }; }); }
function httpGet(url, tenant) { return httpRequest('GET', url, null, tenant); }
function walkJson(value, visit) { if (Array.isArray(value)) { for (const item of value) walkJson(item, visit); return; } if (value && typeof value === 'object') { visit(value); for (const item of Object.values(value)) walkJson(item, visit); } }
function collectObjects(value, predicate) { const out = []; walkJson(value, (obj) => { if (predicate(obj)) out.push(obj); }); return out; }
function jsonText(value) { return JSON.stringify(value || {}); }
function assertIncludes(raw, needle, label) { if (!String(raw || '').includes(needle)) throw new Error(`${label} missing ${needle}`); }
function assertNotIncludes(raw, needle, label) { if (String(raw || '').includes(needle)) throw new Error(`${label} leaked ${needle}`); }
function objectWithExactId(value, id) { const exact = collectObjects(value, (obj) => Object.values(obj || {}).some((v) => v === id)); if (exact.length) return exact.sort((a, b) => jsonText(a).length - jsonText(b).length)[0]; const fuzzy = collectObjects(value, (obj) => jsonText(obj).includes(id)); return fuzzy.sort((a, b) => jsonText(a).length - jsonText(b).length)[0]; }
function operationTrusted(obj) { const text = jsonText(obj); return obj.customer_visible_eligible === true || /正式可信|正式可见|可信价值|FORMAL_OPERATION/.test(text); }
function operationPendingNotTrusted(obj) { const text = jsonText(obj); return obj.customer_visible_eligible !== true && !/正式可信|可信价值结论|正式作业成功|FORMAL_OPERATION/.test(text); }
async function verifyApi(p, baseUrl) { if (!baseUrl) throw new Error('--verify-api requires --base-url'); const base = baseUrl.replace(/\/+$/, ''); const get = async (u) => { const r = await httpGet(base + u, p.tenant); if (!r.status || r.status >= 500) throw new Error(`api failed ${u}: ${r.status}`); return { raw: r.raw, json: r.json }; }; const ae = await get(`/api/v1/as-executed/by-task/${TASK_ID}?tenant_id=${p.tenant}&project_id=${PROJECT_ID}&group_id=${GROUP_ID}`); if (!ae.raw.includes('CONFIRMED')) throw new Error('as-executed by-task missing CONFIRMED formal receipt result'); const op = await get(`/api/v1/reports/operation/${FORMAL_OP}?tenant_id=${p.tenant}&project_id=${PROJECT_ID}&group_id=${GROUP_ID}`); for (const x of ['diagnostic_inputs','prescription','as_executed','as_applied']) assertIncludes(op.raw, x, 'operation report formal chain'); const fr = await get(`/api/v1/reports/field/${FIELD_ID}?tenant_id=${p.tenant}&project_id=${PROJECT_ID}&group_id=${GROUP_ID}`); for (const x of ['field_context','sensing_summary','decision_summary','execution_summary','value_summary','learning_summary']) assertIncludes(fr.raw, x, 'field report formal chain'); if (isC8FormalProfile(p.profile)) { assertNotIncludes(fr.raw, PENDING_OP, 'field report c8 formal profile'); assertNotIncludes(fr.raw, 'PENDING_ACCEPTANCE_REQUIRES_FORMAL_REVIEW', 'field report c8 formal profile'); assertNotIncludes(fr.raw, 'dev_gateway_offline_001', 'field report c8 formal profile'); } const reports = await get('/api/v1/customer/reports'); for (const x of ['OVERVIEW','FIELD','OPERATION','EVIDENCE_VALUE']) assertIncludes(reports.raw, x, 'customer reports report_type coverage'); assertNotIncludes(reports.raw, 'OFFICIAL_CUSTOMER_API', 'customer reports'); const ops = await get('/api/v1/customer/operations'); const expectedOps = isC8FormalProfile(p.profile) ? [FORMAL_OP] : [FORMAL_OP, PENDING_OP]; for (const x of expectedOps) assertIncludes(ops.raw, x, 'customer operations'); if (isC8FormalProfile(p.profile)) assertNotIncludes(ops.raw, PENDING_OP, 'customer operations c8 formal profile'); if (ops.json) { const formal = objectWithExactId(ops.json, FORMAL_OP); if (!formal) throw new Error('customer operations JSON missing formal operation'); if (!operationTrusted(formal)) throw new Error('formal operation is not customer-visible trustworthy'); if (!isC8FormalProfile(p.profile)) { const pending = objectWithExactId(ops.json, PENDING_OP); if (!pending) throw new Error('customer operations JSON missing pending operation'); if (!operationPendingNotTrusted(pending)) throw new Error('pending operation formed a trusted value conclusion'); } } return { ok: true, verify_api: true, base_url: base, profile: p.profile, chain_id: p.chain_id, endpoints: ['/api/v1/as-executed/by-task/:task_id','/api/v1/reports/operation/:operation_id','/api/v1/reports/field/:field_id','/api/v1/customer/reports','/api/v1/customer/operations'] }; }
async function exportDb(p) { return withClient(async (c) => { const out = exportPlan(p); const m = p.manifest.seed_owned_ids; out.tables.field_index_v1 = await readOwned(c, 'field_index_v1', p.tenant, 'field_id', m.fields); out.tables.field_polygon_v1 = await readOwned(c, 'field_polygon_v1', p.tenant, 'field_id', m.fields); for (const table of ['device_index_v1','device_binding_index_v1','device_status_index_v1','device_capability']) out.tables[table] = await readOwned(c, table, p.tenant, 'device_id', m.devices); out.tables.alert_event_index_v1 = await readOwned(c, 'alert_event_index_v1', p.tenant, 'event_id', m.alerts); out.tables.field_memory_v1 = await readOwned(c, 'field_memory_v1', p.tenant, 'memory_id', m.field_memory); out.tables.prescription_contract_v1 = await readOwned(c, 'prescription_contract_v1', p.tenant, 'prescription_id', m.prescriptions); out.tables.approval_requests_v1 = await readOwned(c, 'approval_requests_v1', p.tenant, 'approval_request_id', m.approval_requests); out.tables.operation_state_v1_optional = await readOwned(c, 'operation_state_v1', p.tenant, 'operation_id', m.operations); out.tables.roi_ledger_v1_optional = await readOwned(c, 'roi_ledger_v1', p.tenant, 'roi_ledger_id', [ROI_ID]); const factRows = (await c.query('SELECT fact_id, occurred_at, source, record_json FROM facts WHERE fact_id LIKE $1 ORDER BY fact_id', [`${p.prefix}_%`])).rows; out.facts_by_type = factByType(factRows); out.export_db_json = true; return out; }); }
async function ownedCounts(c, p) { const m = p.manifest.seed_owned_ids; const counts = {}; counts.facts = Number((await c.query('SELECT count(*) FROM facts WHERE fact_id LIKE $1', [`${p.prefix}_%`])).rows[0].count); counts.fields = (await readOwned(c, 'field_index_v1', p.tenant, 'field_id', m.fields)).length; counts.devices = (await readOwned(c, 'device_index_v1', p.tenant, 'device_id', m.devices)).length; counts.alerts = (await readOwned(c, 'alert_event_index_v1', p.tenant, 'event_id', m.alerts)).length; counts.field_memory = (await readOwned(c, 'field_memory_v1', p.tenant, 'memory_id', m.field_memory)).length; counts.prescriptions = (await readOwned(c, 'prescription_contract_v1', p.tenant, 'prescription_id', m.prescriptions)).length; counts.operations_optional = (await readOwned(c, 'operation_state_v1', p.tenant, 'operation_id', m.operations)).length; counts.approvals_optional = (await readOwned(c, 'approval_requests_v1', p.tenant, 'approval_request_id', m.approval_requests)).length; counts.roi_optional = (await readOwned(c, 'roi_ledger_v1', p.tenant, 'roi_ledger_id', [ROI_ID])).length; return counts; }
async function cleanup(p, doApply) { return withClient(async (c) => { const counts = await ownedCounts(c, p); if (!doApply) return { ok: true, cleanup: true, apply: false, tenant: p.tenant, profile: p.profile, will_delete: counts, warnings: ['cleanup dry-run only'] }; let locked = false; await c.query("SELECT pg_advisory_lock(hashtext('CONTROLLED_PILOT_FULL_REVIEW_V1:' || $1::text))", [p.tenant]); locked = true; try { await c.query('BEGIN'); await clearOwnedBeforeApply(c, p); await c.query('COMMIT'); return { ok: true, cleanup: true, apply: true, tenant: p.tenant, profile: p.profile, deleted: counts }; } catch (e) { await c.query('ROLLBACK').catch(() => {}); throw e; } finally { if (locked) await c.query("SELECT pg_advisory_unlock(hashtext('CONTROLLED_PILOT_FULL_REVIEW_V1:' || $1::text))", [p.tenant]).catch(() => {}); } }); }
async function verifyClean(p) { return withClient(async (c) => { const counts = await ownedCounts(c, p); if (Object.values(counts).some(Number)) throw new Error(`seed-owned rows remain: ${JSON.stringify(counts)}`); return { ok: true, verify_clean: true, tenant: p.tenant, profile: p.profile, counts }; }); }
function assertNoBadPlan(p) { const text = JSON.stringify(exportPlan(p)).toLowerCase(); for (const x of ['field_id=...', 'device_id=...', '"..."', 'sim' + '_trace', 'dev' + '_source']) if (text.includes(x)) throw new Error(`forbidden marker in plan: ${x}`); }
async function main() { const args = parseArgs(process.argv); const p = makePlan(args.tenant, args.profile); assertNoBadPlan(p); if (args.mode === 'dry-run') writeOut(dryRun(p), args.out); else if (args.mode === 'export-json') writeOut(exportPlan(p), args.out); else if (args.mode === 'apply') writeOut(await apply(p, args.baseUrl), args.out); else if (args.mode === 'verify') writeOut(await verify(p), args.out); else if (args.mode === 'verify-api') writeOut(await verifyApi(p, args.baseUrl), args.out); else if (args.mode === 'export-db-json') writeOut(await exportDb(p), args.out); else if (args.mode === 'cleanup') writeOut(await cleanup(p, args.apply), args.out); else if (args.mode === 'verify-clean') writeOut(await verifyClean(p)); else writeOut(dryRun(p), args.out); }
main().catch((e) => { console.error(JSON.stringify({ ok: false, error: String(e && e.message ? e.message : e) }, null, 2)); process.exit(1); });
